    出(p => p.M(X(5.55), Z(5.75))
        .C(X(5.3), Z(6.25), X(5.05), Z(6.75), X(4.8), Z(7.25)), 0.56);
    出(p => p.M(X(4.95), Z(6.0))
        .C(X(5.45), Z(6.5), X(6.05), Z(7.1), X(6.55), Z(7.65)), 0.56);
    出(p => p.M(X(5.0), Z(5.7)).L(X(5.05), Z(8.5))
        .C(X(5.08), Z(8.75), X(5.2), Z(8.95), X(5.4), Z(9.1)), 0.54);
    // 大框嵌四目箱（中豎貫）
    線(p => p.M(X(0.64), Z(11.2)).C(X(2.8), Z(11.1), X(5.5), Z(11.2), X(7.31), Z(11.1)), 0.64);
    線(p => p.M(X(0.62), Z(11.25)).L(X(0.61), Z(16.35)), 0.58);
    線(p => p.M(X(7.33), Z(11.15)).L(X(7.32), Z(16.25)), 0.58);
    出(p => p.M(X(3.98), Z(11.15)).L(X(4.0), Z(16.5)), 0.56);
    線(p => p.M(X(0.95), Z(12.55)).L(X(3.65), Z(12.49)), 0.52);
    線(p => p.M(X(0.93), Z(12.58)).L(X(0.92), Z(13.5)), 0.5);
    線(p => p.M(X(3.67), Z(12.51)).L(X(3.66), Z(13.44)), 0.5);
