    線(p => p.M(X(0.97), Z(13.5)).L(X(3.66), Z(13.44)), 0.52);
    線(p => p.M(X(4.61), Z(12.5)).L(X(7.23), Z(12.44)), 0.52);
    線(p => p.M(X(4.59), Z(12.53)).L(X(4.58), Z(13.45)), 0.5);
    線(p => p.M(X(7.25), Z(12.46)).L(X(7.24), Z(13.38)), 0.5);
    出(p => p.M(X(5.0), Z(12.8)).C(X(5.25), Z(13.05), X(6.15), Z(13.1), X(6.85), Z(12.85)), 0.46);
    線(p => p.M(X(4.63), Z(13.45)).L(X(7.24), Z(13.39)), 0.52);
    線(p => p.M(X(0.68), Z(13.95)).L(X(7.28), Z(13.85)), 0.56);
    線(p => p.M(X(0.95), Z(14.45)).L(X(3.65), Z(14.39)), 0.52);
    線(p => p.M(X(0.93), Z(14.48)).L(X(0.92), Z(15.4)), 0.5);
    線(p => p.M(X(3.67), Z(14.41)).L(X(3.66), Z(15.34)), 0.5);
    出(p => p.M(X(1.35), Z(14.75)).C(X(1.6), Z(15.0), X(2.5), Z(15.05), X(3.2), Z(14.8)), 0.46);
    線(p => p.M(X(0.97), Z(15.4)).L(X(3.66), Z(15.34)), 0.52);
    線(p => p.M(X(4.61), Z(14.4)).L(X(7.23), Z(14.34)), 0.52);
